{
    internal static ReadOnlySpan<ushort> LowBits => s_lowBits;

    internal static ReadOnlySpan<uint> Astralness => s_astralness;

    private static readonly ushort[] s_lowBits = DecodePackedU16(LowBitsBase64);
    private static readonly uint[] s_astralness = DecodePackedU32(AstralnessBase64);

    private static ushort[] DecodePackedU16(string base64)
    {
        byte[] bytes = Convert.FromBase64String(base64);
        ushort[] values = new ushort[bytes.Length / 2];
        for (int index = 0; index < values.Length; index++)
        {
            int byteIndex = index * 2;
            values[index] = (ushort)(bytes[byteIndex] | (bytes[byteIndex + 1] << 8));
        }

        return values;
    }

    private static uint[] DecodePackedU32(string base64)
    {
        byte[] bytes = Convert.FromBase64String(base64);
        uint[] values = new uint[bytes.Length / 4];
        for (int index = 0; index < values.Length; index++)
        {
            int byteIndex = index * 4;
            values[index] = (uint)(bytes[byteIndex] | (bytes[byteIndex + 1] << 8) | (bytes[byteIndex + 2] << 16) | (bytes[byteIndex + 3] << 24));
        }

        return values;
    }

